+              NewC = ConstantFP::get(SrcTy, MidPrev);
+              if (!CEven && Pred == FCmpInst::FCMP_OGE)
+                NewPred = FCmpInst::FCMP_OGT;
+              else if (!CEven && Pred == FCmpInst::FCMP_UGE)
+                NewPred = FCmpInst::FCMP_UGT;
+              break;
+            case FCmpInst::FCMP_OGT:
+            case FCmpInst::FCMP_UGT:
+              // (float)X > C  <=>  X >= MidNext (if next even) or X > MidNext (if next odd)
+              NewC = ConstantFP::get(SrcTy, MidNext);
+              if (NextEven && Pred == FCmpInst::FCMP_OGT)
+                NewPred = FCmpInst::FCMP_OGE;
+              else if (NextEven && Pred == FCmpInst::FCMP_UGT)
+                NewPred = FCmpInst::FCMP_UGE;
+              break;
+            case FCmpInst::FCMP_OLE:
+            case FCmpInst::FCMP_ULE:
+              // (float)X <= C  <=>  X <= MidNext (if next odd) or X < MidNext (if next even)
+              NewC = ConstantFP::get(SrcTy, MidNext);
+              if (NextEven && Pred == FCmpInst::FCMP_OLE)
+                NewPred = FCmpInst::FCMP_OLT;
+              else if (NextEven && Pred == FCmpInst::FCMP_ULE)
